import React, { useState } from 'react';
import axios from 'axios';

export default function Dashboard() {
  const [flightNumber, setFlightNumber] = useState('');
  const [data, setData] = useState([]);

  const fetchData = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/flights/${flightNumber}`
      );
      setData(res.data);
    } catch (err) {
      console.error(err);
      alert('Error fetching flight data');
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>✈️ Flight Tracker</h1>

      <input
        placeholder="Enter Flight (e.g. AI)"
        value={flightNumber}
        onChange={(e) => setFlightNumber(e.target.value)}
        style={{ padding: 10, marginRight: 10 }}
      />

      <button onClick={fetchData}>Track</button>

      <div style={{ marginTop: 20 }}>
        {data.length === 0 && <p>No flights found</p>}

        {data.map((flight, index) => (
          <div
            key={index}
            style={{
              background: '#eee',
              padding: 10,
              marginTop: 10,
              borderRadius: 8,
            }}
          >
            <p><b>Callsign:</b> {flight.callsign}</p>
            <p><b>Country:</b> {flight.country}</p>
            <p><b>Lat:</b> {flight.latitude}</p>
            <p><b>Lon:</b> {flight.longitude}</p>
            <p><b>Altitude:</b> {flight.altitude}</p>
            <p><b>Velocity:</b> {flight.velocity}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
